            stderr = stderr.get('alias') or stderr.get('mean') or stderr.get('value')
        tasks[task_name] = {
            'accuracy': acc,
            'accuracy_stderr': stderr
        }
        print(f'{task_name}: acc={acc}, stderr={stderr}')
